from functools import wraps
from flask import Flask, session, redirect, url_for, request, render_template_string
from urllib.parse import urlparse, urljoin

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

def is_safe_url(target):
    ref_url = urlparse(request.host_url)
    test_url = urlparse(urljoin(request.host_url, target))
    return test_url.scheme in ('http', 'https') and ref_url.netloc == test_url.netloc

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            session['next'] = request.url
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

def redirect_to_intended_destination(default_destination='dashboard'):
    next_url = session.pop('next', None) or request.args.get('next')
    
    if next_url and is_safe_url(next_url):
        return redirect(next_url)
    
    return redirect(url_for(default_destination))

@app.route('/')
def index():
    return render_template_string('''
        <h1>Home Page</h1>
        <a href="{{ url_for('protected') }}">Protected Page</a><br>
        <a href="{{ url_for('dashboard') }}">Dashboard</a><br>
        <a href="{{ url_for('profile') }}">Profile</a><br>
        <a href="{{ url_for('logout') }}">Logout</a>
    ''')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        
        if username == 'admin' and password == 'password':
            session['user_id'] = 1
            session['username'] = username
            return redirect_to_intended_destination()
        else:
            return render_template_string('''
                <h2>Login Failed</h2>
                <p>Invalid credentials</p>
                <a href="{{ url_for('login') }}">Try Again</a>
            ''')
    
    return render_template_string('''
        <h2>Login</h2>
        <form method="post">
            <label>Username: <input type="text" name="username" value="admin"></label><br>
            <label>Password: <input type="password" name="password" value="password"></label><br>
            <button type="submit">Login</button>
        </form>
        <p>Use username: admin, password: password</p>
    ''')

@app.route('/dashboard')
@login_required
def dashboard():
    return render_template_string('''
        <h1>Dashboard</h1>
        <p>Welcome, {{ session.username }}!</p>
        <a href="{{ url_for('index') }}">Home</a><br>
        <a href="{{ url_for('logout') }}">Logout</a>
    ''')

@app.route('/profile')
@login_required
def profile():
    return render_template_string('''
        <h1>Profile Page</h1>
        <p>User: {{ session.username }}</p>
        <a href="{{ url_for('index') }}">Home</a><br>
        <a href="{{ url_for('logout') }}">Logout</a>
    ''')

@app.route('/protected')
@login_required
def protected():
    return render_template_string('''
        <h1>Protected Page</h1>
        <p>This page requires authentication</p>
        <a href="{{ url_for('index') }}">Home</a><br>
        <a href="{{ url_for('logout') }}">Logout</a>
    ''')

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)